import java.io.*;import java.util.*;
public class Solution{public static void main(String[]args)throws Exception{Scanner sc=new Scanner(System.in);if(!sc.hasNextInt())return;int t=sc.nextInt();StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=sc.nextInt(), k=sc.nextInt();ArrayDeque<String> q=new ArrayDeque<>();for(int i=0;i<n;i++)q.add(sc.next());Map<String,Integer> served=new HashMap<>();ArrayList<String> leave=new ArrayList<>();int service=0;while(!q.isEmpty()){String name=q.poll();service++;int c=served.getOrDefault(name,0)+1;served.put(name,c);if(service%k==0 && c==1)q.add(name);else leave.add(name);}if(tc>0)out.append('\n');for(int i=0;i<leave.size();i++){if(i>0)out.append(", ");out.append(leave.get(i));}}System.out.print(out);}}
